public class Cidr {
    static long toInt(String ip) {
        String[] o = ip.split("\\.");
        long v = 0;
        for (String part : o) v = (v << 8) | Integer.parseInt(part);
        return v & 0xFFFFFFFFL;
    }
    static String toIp(long v) {
        return String.format("%d.%d.%d.%d",
            (v >> 24) & 0xFF, (v >> 16) & 0xFF, (v >> 8) & 0xFF, v & 0xFF);
    }
    public static String describe(String cidr) {
        String[] parts = cidr.split("/");
        long ip = toInt(parts[0]);
        int prefix = Integer.parseInt(parts[1]);
        long mask = prefix == 0 ? 0L : (0xFFFFFFFFL << (32 - prefix)) & 0xFFFFFFFFL;
        long network = ip & mask;
        long broadcast = network | (~mask & 0xFFFFFFFFL);
        long total = 1L << (32 - prefix);
        long usable = prefix >= 31 ? total : total - 2;  // /31, /32 have no net/bcast reserved pair
        return "network=" + toIp(network)
             + " broadcast=" + toIp(broadcast)
             + " mask=" + toIp(mask)
             + " usableHosts=" + usable;
    }
    // describe("192.168.1.130/26") ->
    //   network=192.168.1.128 broadcast=192.168.1.191 mask=255.255.255.192 usableHosts=62
}

import java.util.concurrent.ThreadLocalRandom;
import java.util.function.Supplier;

public class Retry {
    public interface Call<T> { T run() throws Exception; }

    static boolean retryable(Exception e) {
        // Retry transient transport/server faults, not client (4xx) mistakes.
        if (e instanceof java.net.SocketTimeoutException) return true;
        if (e instanceof java.io.IOException) return true;        // conn reset, etc.
        if (e instanceof HttpException h) return h.status >= 500; // 5xx only
        return false;
    }

    public static <T> T withBackoff(Call<T> call, int maxAttempts,
                                    long baseMs, long capMs) throws Exception {
        Exception last = null;
        for (int attempt = 0; attempt < maxAttempts; attempt++) {
            try {
                return call.run();
            } catch (Exception e) {
                last = e;
                if (!retryable(e) || attempt == maxAttempts - 1) throw e;
                long exp = Math.min(capMs, baseMs * (1L << attempt)); // base * 2^attempt, capped
                long sleep = ThreadLocalRandom.current().nextLong(exp + 1); // FULL jitter [0, exp]
                Thread.sleep(sleep);
            }
        }
        throw last;
    }

    static class HttpException extends Exception { final int status; HttpException(int s){this.status=s;} }
}
